sys_script_include.script:
// Name: AlationOAuthDiscovery
// Scope: x_alati_snow_intgr
var AlationOAuthDiscovery = Class.create();
AlationOAuthDiscovery.prototype = {
  initialize: function () {},

  // Returns { ok:true, oauth: { token_url, client_id, ... } }
  discover: function () {
    var regName = String(gs.getProperty("x_alati_snow_intgr.oauth_registry_name") || "").trim();

    // ServiceNow token endpoint (standard)
    var tokenUrl = (gs.getProperty("glide.servlet.uri") || "").replace(/\/+$/,"") + "/oauth_token.do";

    // OAuth Application Registry table
    var authEnt = new GlideRecord("oauth_entity");
    authEnt.addQuery("name", regName);
    authEnt.addQuery("active", true);
    authEnt.setLimit(1);
    authEnt.query();

    if (!authEnt.next()) {
      return { ok:false, error:"OAuth Application Registry not found with name: " + regName };
    }

    var clientId = String(authEnt.getValue("client_id") || "").trim();
    if (!clientId) {
      return { ok:false, error:"OAuth registry missing client_id (name: " + regName + ")" };
    }

	var clientSecret = String(gs.getProperty("x_alati_snow_intgr.oauth_client_secret") || "").trim();

    // If you want to enforce a scope, hardcode or store in property; else blank
    var scope = "";

	var username = String(gs.getProperty("x_alati_snow_intgr.integration_user_name") || "").trim(); // "alation_integration"
    var password = String(gs.getProperty("x_alati_snow_intgr.integration_user_password") || "").trim();

    if (!password) return { ok:false, error:"Missing integration user password property" };

    return {
      ok: true,
      oauth: {
      token_url: tokenUrl,
      client_id: clientId,
      client_secret: clientSecret,
      username: username,
      password: password,
    }
  };
  },

  type: "AlationOAuthDiscovery"
};
